export const milliSeconds2Seconds = ({
  subMenuOpenDelay,
  subMenuCloseDelay,
}: {
  subMenuOpenDelay?: number;
  subMenuCloseDelay?: number;
}) => {
  const ret: {
    subMenuOpenDelay?: number;
    subMenuCloseDelay?: number;
  } = {};
  if (typeof subMenuOpenDelay === 'number') {
    ret.subMenuOpenDelay = subMenuOpenDelay / 1000;
  }
  if (typeof subMenuCloseDelay === 'number') {
    ret.subMenuCloseDelay = subMenuCloseDelay / 1000;
  }
  return ret;
};

export const isSubMenu = (c: any) => c.type?.isSubMenu;
